module adder_32bit(
    input [31:0] A,
    input [31:0] B,
    output [31:0] S,
    output C32
);

wire [31:0] carry;

genvar i;
generate
    for (i = 0; i < 32; i = i + 1) begin
        if (i == 0) begin
            assign {carry[i], S[i]} = A[i] + B[i];
        end else begin
            assign {carry[i], S[i]} = A[i] + B[i] + carry[i-1];
        end
    end
endgenerate

assign C32 = carry[31];

endmodule
